import type * as React from 'react';

import {Spinner} from '@/components/ui/spinner';
import {cn} from '@/lib/utils';

type LoadingStateProps = {
  title: React.ReactNode;
  content?: React.ReactNode;
  className?: string;
};

function LoadingState({title, content, className}: LoadingStateProps) {
  return (
    <output
      data-slot="loading-state"
      className={cn(
        'flex flex-col items-center justify-center gap-4 py-16 text-center',
        className
      )}
    >
      <Spinner className="size-10 text-muted-foreground" aria-hidden="true" />
      <div className="space-y-1">
        <p className="text-sm font-label text-foreground">{title}</p>
        {content && (
          <p className="max-w-sm text-sm text-muted-foreground">{content}</p>
        )}
      </div>
    </output>
  );
}

export {LoadingState};
export type {LoadingStateProps};
